const incoming = items[0].json;
const message = incoming.message || incoming.text || '';
const symbol = incoming.symbol || incoming.ticker || 'TSX:RY';
const now = Date.now();
const staticData = this.getWorkflowStaticData('workflow');
const lastMessages = Array.isArray(staticData.lastMessages) ? staticData.lastMessages : [];
lastMessages.push({ role: 'user', content: message, timestamp: now });
const cutoff = now - 5 * 60 * 1000;
const recentMessages = lastMessages.filter((m) => m.timestamp >= cutoff);
staticData.lastMessages = recentMessages;
return [{ json: { ...incoming, message, symbol, lastMessages: recentMessages } }];

const incoming = items[0].json;
const quote = incoming.quoteResponse?.result?.[0] || {};
const lastMessages = incoming.lastMessages || [];
const financialData = {
  symbol: incoming.symbol || 'TSX:RY',
  name: quote.longName || quote.shortName || incoming.symbol,
  currency: quote.currency || 'CAD',
  regularMarketPrice: quote.regularMarketPrice,
  previousClose: quote.regularMarketPreviousClose,
  open: quote.regularMarketOpen,
  dayHigh: quote.regularMarketDayHigh,
  dayLow: quote.regularMarketDayLow,
  marketCap: quote.marketCap,
  fiftyTwoWeekHigh: quote.fiftyTwoWeekHigh,
  fiftyTwoWeekLow: quote.fiftyTwoWeekLow,
  trailingPE: quote.trailingPE,
  forwardPE: quote.forwardPE,
  marketState: quote.marketState
};
const prompt = `Vous êtes un analyste financier expert du site Yahoo Finance Canada.

Message analyste : ${incoming.message || incoming.text || 'Résumé financier demandé.'}

Données Yahoo Finance Canada : ${JSON.stringify(financialData, null, 2)}

Historique de conversation (5 dernières minutes) : ${JSON.stringify(lastMessages, null, 2)}

Fournissez un résumé clair et structuré pour un analyste financier, en soulignant les indicateurs clés, tendances, risques et points de vigilance.`;
return [{ json: { symbol: incoming.symbol, financialData, lastMessages, prompt } }];

const incoming = items[0].json;
const responseText = incoming.choices?.[0]?.message?.content || incoming.choices?.[0]?.text || '';
const staticData = this.getWorkflowStaticData('workflow');
const lastMessages = Array.isArray(staticData.lastMessages) ? staticData.lastMessages : [];
const now = Date.now();
lastMessages.push({ role: 'assistant', content: responseText, timestamp: now });
const cutoff = now - 5 * 60 * 1000;
staticData.lastMessages = lastMessages.filter((m) => m.timestamp >= cutoff);
return [{ json: { symbol: incoming.symbol || '', summary: responseText, source: 'Yahoo Finance Canada', timestamp: new Date().toISOString(), memory: staticData.lastMessages, raw: incoming } }];
